import { createClient } from "@supabase/supabase-js";
import * as dotenv from "dotenv";
import * as path from "path";

dotenv.config({ path: path.resolve(__dirname, "../.env.local") });

const supabaseUrl = process.env.NEXT_PUBLIC_OMNISKILLS_SUPABASE_URL!;
const supabaseKey = process.env.OMNISKILLS_SERVICE_KEY!;

if (!supabaseUrl || !supabaseKey) {
  console.error("Missing NEXT_PUBLIC_OMNISKILLS_SUPABASE_URL or OMNISKILLS_SERVICE_KEY");
  process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseKey);

const CATEGORIES = [
  "code-assistant", "writing", "data-analysis", "research",
  "automation", "design", "devops", "productivity", "education", "security"
] as const;

type Category = typeof CATEGORIES[number];

interface SkillDef {
  slug: string;
  name: string;
  tagline: string;
  description: string;
  author: string;
  url: string;
  category: Category;
  categories: Category[];
  keywords: string[];
}

function randInt(min: number, max: number) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

