// ── Combine all skills ──
const allSkills: SkillDef[] = [
  ...azureSkills,
  ...awsSkills,
  ...gcpSkills,
  ...frameworkSkills,
  ...databaseSkills,
  ...aiMlSkills,
  ...devopsSkills,
  ...testingSkills,
  ...mobileSkills,
  ...productivitySkills,
  ...miscSkills,
];

async function main() {
  console.log(`Total skills to import: ${allSkills.length}`);

  // Check current count
  const { count: existingCount } = await supabase
    .from("skills")
    .select("*", { count: "exact", head: true });
  console.log(`Existing skills in database: ${existingCount}`);

  // Prepare rows with gen2- prefix
  const rows = allSkills.map((s) => ({
    name: s.name,
    slug: `gen2-${s.slug}`,
    tagline: s.tagline,
    description: s.description,
    author: s.author,
    url: s.url,
    category: s.category,
    categories: s.categories,
    keywords: s.keywords,
    pricing_type: "free",
    install_count: randInt(2000, 15000),
    is_new: Math.random() < 0.15,
    is_trending: Math.random() < 0.1,
  }));

  // Batch upsert (50 per batch)
  const BATCH_SIZE = 50;
  let imported = 0;
  let errors = 0;

  for (let i = 0; i < rows.length; i += BATCH_SIZE) {
    const batch = rows.slice(i, i + BATCH_SIZE);
    const { data, error } = await supabase
      .from("skills")
      .upsert(batch, { onConflict: "slug" })
      .select("slug");

    if (error) {
      console.error(`Batch ${Math.floor(i / BATCH_SIZE) + 1} error:`, error.message);
      errors++;
    } else {
      imported += data?.length ?? batch.length;
      console.log(`Batch ${Math.floor(i / BATCH_SIZE) + 1}: inserted ${data?.length ?? batch.length} skills`);
    }
  }

  console.log(`\nImported: ${imported} skills`);
  if (errors > 0) console.log(`Batches with errors: ${errors}`);

  // Get new total
  const { count: newCount } = await supabase
    .from("skills")
    .select("*", { count: "exact", head: true });
  console.log(`New total skills: ${newCount}`);

  // Category breakdown
  const { data: catData } = await supabase
    .from("skills")
    .select("category");

  if (catData) {
    const counts: Record<string, number> = {};
    catData.forEach((r: any) => {
      counts[r.category] = (counts[r.category] || 0) + 1;
    });
    console.log("\nCategory breakdown:");
    Object.entries(counts)
      .sort((a, b) => b[1] - a[1])
      .forEach(([cat, count]) => console.log(`  ${cat}: ${count}`));
  }
}

main().catch(console.error);
